var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"……이 자리에 서니, 어쩐지 꼬맹이 시절로 돌아간 것 같군요.","JPN":"……ここにいると、なんだか子どもの頃に戻ったような気分です。","ENG":"Standing here reminds me of the time when I was a kid.","TWN":"……站在這裡，感覺好像回到小時候。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"힘없고, 겁쟁이였던 제게 아버지는 총 쏘는 법을 가르쳐 주셨죠.","JPN":"力もなく臆病者だった俺に、父は銃の撃ち方を教えてくれました。","ENG":"I was a meek cowardly boy, and my father taught me how to shoot a gun.","TWN":"爸爸教軟弱無能的我如何使用槍。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"카운터가 되고 힘을 얻은 후에는 이 주먹으로 모두를 구할 수 있을 거라 자신해왔고요.","JPN":"カウンターになって力を得た後は、この拳でみんなを救えると自信を持っていたんです。","ENG":"Since I became a Counter, I believed that I could save everyone with my bare hands.","TWN":"成為制裁者獲得能力後，我就一直相信能靠著這雙拳頭拯救所有人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"하지만 현실에는 한계가 있었죠.","JPN":"ですが、現実には限界がありました。","ENG":"But there are always limits in the real world.","TWN":"但現實和理想是有落差的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"약한 소리 하기는 싫지만, 이번에는 정말 제 동료들이 아니었다면 위험했으니까요.","JPN":"弱音を吐きたくありませんが、今回は同僚たちがいなかったら本当に危ないところでしたからね。","ENG":"I don’t want to sound weak, but I could have been in a real trouble if it wasn’t for my colleagues this time.","TWN":"我不喜歡示弱，但這次要不是我的夥伴，真的是非常驚險。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"하지만 제 마음만큼은 여전히 변함없습니다.","JPN":"しかし、俺の気持ちだけは何も変わっていません。","ENG":"Still, my mind hasn’t changed.","TWN":"但我的想法還是一樣沒變。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"적당히 현실과 타협하면서 사는 건 적성에 안 맞거든요.","JPN":"適当に現実と折り合い付けて生きていくのは、性に合わないんですよ。","ENG":"I don’t like compromising with reality.","TWN":"和現實妥協不是我的風格。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"또 압니까? 이렇게 몇 번 한계를 뛰어넘다 보면 정말로 모두를 구하게 될지.","JPN":"今はまだまだですが、こうして何度か限界を越えていくうちに、本当に皆を救えるようになれるかもしれません。","ENG":"Who knows? If I break my limits like this several times, I might actually be able to save everyone.","TWN":"而且誰知道呢？或許再這樣突破極限幾次，我真的可以拯救所有人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"하핫, 바보 같은 생각이라고 해도 어쩔 수 없습니다.","JPN":"ははっ、馬鹿げた夢だと思われても仕方ありません。","ENG":"Haha, you might think I’m stupid, but this is what I am.","TWN":"哈哈～就算你覺得我很傻也無所謂。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"……간절함이 없는 힘은 금방 사람을 자만하게 만들죠.","JPN":"……切実さのない力は、すぐに人を傲慢にしてしまいます。","ENG":"Power without desperation will make you conceited.","TWN":"……要是沒有這種心志，能力很快就會使人驕傲。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"결국, 지금껏 지나쳐왔던 순간, 순간이 절 이 자리로 이끌었다고……. 전 그렇게 믿습니다.","JPN":"結局今まで歩んできた道、その経験が俺をこの場所に導いてくれたと……そう信じています。","ENG":"I believe that every moment that I went through brought me here.","TWN":"我相信是過去所經歷過的每個瞬間……將我引導到現在這個位置的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"그러니 이 선택에 후회는 없습니다.","JPN":"ですから、この選択に後悔はありません。","ENG":"I have no regret over my choice.","TWN":"所以我從未對這個選擇感到後悔過。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"이 자리에서 확실히 말해두죠.","JPN":"この場ではっきり言わせていただきます。","ENG":"Let me be clear.","TWN":"我可以在這裡大聲說，"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"저는 이익이 아니라, 의무로서 사람을 구하고 싶습니다.","JPN":"俺は利益のためではなく、義務として人を救いたいです。","ENG":"I want to save people as my duty, not for a profit.","TWN":"但我想要的不是委託費，而是基於義務救人。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FOOLSDAY_JAKE_CONTEST_JACY","text":{"KOREA":"그것만큼은 언제까지나 변할 일 없을 겁니다.","JPN":"それだけはいつまでも変わることはないでしょう。","ENG":"And that will never change.","TWN":"這一點是絕對不會改變的！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FOOLSDAY_JAKE_CONTEST_JACY","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};